# DE 1700.  Hannover Hbf - Hamm (Westf)
#
let hh = path("d3.de.h.1700");

with detail = 3,
     railway = :first :double :cat:ac15 :pax
{
    with link = "point.de.Hannover-Hbf", railway = :station {
        track(hh[:han - 0.5sw, :han + 0.5sw]);
        track(hh[:han - 0.5sw, :han + 0.5sw] << 1ms << 1md);
        track(hh[:han - 0.5sw, :han + 0.5sw] << 2ms << 2md);
        marker(:left :de.bf, hh[:han] << 2ms << 2.5md);
        slabel(:right :bold, hh[:han] >> 0.5md + (1dt, -0.5dt),
            "Hannover Hbf"
        );
    }

    with link = "line.de.1700" {
        track(:lor, hh[:han + 0.49sw, :hbu]);
    }

    with link = "point.de.Hannover-Burg", railway = :station {
        marker(:right :de.bft :nopax, hh[:hbu] >> 0.5md);
    }

    with link = "line.de.1700" {
        track(:lor, hh[:hbu, :hbu.yc]);
        track(:lor:ror :casing, hh[:hbu.yc - 0.1dl, :hle.yw + 0.1dl]);
        track(:lor:ror, hh[:hle.yw, :hle - 0.49sw]);
        track(:lor:ror, hh[:hle - 0.5sw, :hle + 0.5sw]);
        track(:lor:ror, hh[:hle + 0.49sw, :kur - 1.9dl]);
        track(:lor:ror, hh[:kur - 2dl, :kur + 0.1dl]);
        track(:lor:ror, hh[:kur, :lea - 2dl]);
    }

    with link = "point.de.Letter-Abzw", railway = :station {
        marker(:right :de.abzw,
            hh[:lea - 2dl] >> 1.5md >> 1ms,
            hh[:lea - 2dl] << 1.5md << 1ms
        );
        slabel(:top :xsmall,
            hh[:lea - 2dl] >> 1.5md >> 1ms >> 1sh + (0dt, -0.5dt),
            vbox(:center:base, "Letter", "(Abzw)")
        );
    }

    with link = "line.de.1700" {
        track(:lor:ror, hh[:lea - 2.1dl, :let.yl + 0.1dl]);
        track(:lor:ror, hh[:let.yl, :let + 0.5sw]);
        track(:lor:ror, hh[:let + 0.49sw, :sem]);
        track(:lor:ror, hh[:sem, :see - 549m]);
    }

    with link = "point.de.Seelze", railway = :station {
        # DE 1700
        track(hh[:see - 550m, :see + 450m]);

        # DE 1705 dn
        track(:single,
                hh[:see - 550m, :see + 420m - 1dl] >> 0.5md >> 1ms >> 0.5mt
            --  hh[:see + 420m, :see + 421m] >> 0.5md << 0.5mt
        );

        # DE 1705 up
        track(:single,
                hh[:see - 551m, :see - 550m] >> 1ms >> 1.5md << 0.5mt
            --  hh[:see - 550m + 1dl, :see - 550m + 1.1dl]
                >> 0.5md >> 1ms >> 0.5mt
        );

        marker(:right :de.bf, hh[:see] >> 0.5md >> 1ms >> 1mt);
        slabel(:top :bold,
            hh[:see] >> 0.5md >> 1ms >> 1mt >> 1sh + (0.5dt, -0.3dt),
            "Seelze"
        );
    }

    with link = "line.de.1700" {
        track(:lor, hh[:see + 450m, :sew]);
    }

    with link = "point.de.point.de.Seelze-West", railway = :station {
        marker(:left :de.bft :nopax, hh[:sew] << 1ms << 1.5md);
        slabel(:bottom :xsmall,
            hh[:sew] << 1ms << 1.5md << 1sh + (-3dt, 0.3dt),
            "Seelze West"
        );
    }

    with link = "line.de.1700" {
        track(:lor, hh[:sew, :lod]);
    }

    with link = "point.de.Lohnde-Seelze", railway = :station {
        marker(:right :de.bk :removed, hh[:lod] >> 0.5md);
        slabel(:right :removed, hh[:lod] >> 0.5md >> 1sh + (1.3dt, -0.3dt),
            "Lohnde"
        );
    }

    with link = "line.de.1700" {
        track(:lor, hh[:lod, :ded - 0.49sw]);
    }

    with link = "point.de.Dedensen-Gümmer", railway = :station {
        track(hh[:ded - 0.5sw, :ded + 0.5sw]);
        track(:nopax, hh[:ded - 0.5sw, :ded + 0.5sw] << 1ms << 1md);
        marker(:right :de.hp, hh[:ded] >> 0.5md);
        slabel(:right, hh[:ded] >> 0.5md >> 1sh + (1.3dt, -0.3dt),
            "Dedensen-Gümmer*"
        );
    }

    with link = "line.de.1700" {
        track(:lor, hh[:ded + 0.49sw, :gum]);
        with layer = -1 track(:lor:ror, hh[:gum, :gum.yw + 1.1md]);
        track(:lor:ror, hh[:gum.yw + 1md, :wun - 1099m]);
        track(:lor:ror, hh[:wun - 1100m, :wun - 900m]);
    }

    with link = "point.de.Wunstorf", railway = :station {
        let wb = path("d3.de.1740");

        # DE 1750
        track(:nopax,
                hh[:wun - 900m, :wun + 450m - 2dl] << 1ms << 1md
            --  hh[:wun + 450m, :wun + 451m]
